APP_NAME = "office_face_recognition_api"
DEFAULT_MODEL_PATH = os.environ.get("FACE_MODEL_PATH", "./face_model.pkl")
DEFAULT_EMPLOYEE_DIR = os.environ.get("EMPLOYEE_DIR", "./employees")
DEFAULT_API_KEY = os.environ.get("API_KEY", "")
DEFAULT_DETECTION_MODEL = os.environ.get("DETECTION_MODEL", "hog")  # hog|cnn
DEFAULT_NUM_JITTERS = int(os.environ.get("NUM_JITTERS", "1"))
