DEFAULT_MIN_FACE_SIZE = int(os.environ.get("MIN_FACE_SIZE", "40"))  # min width/height px
DEFAULT_MAX_FACES = int(os.environ.get("MAX_FACES", "5"))

_model_lock = threading.RLock()
_model = None


class TrainRequest(BaseModel):
    employee_dir: str = DEFAULT_EMPLOYEE_DIR
    model_path: str = DEFAULT_MODEL_PATH
    detection_model: str = DEFAULT_DETECTION_MODEL
    num_jitters: int = DEFAULT_NUM_JITTERS
    min_face_size: int = DEFAULT_MIN_FACE_SIZE


class PredictResponse(BaseModel):
    model_version: str
    faces_detected: int
    results: List[Dict]


def _require_deps():
    if face_recognition is None:
        raise HTTPException(status_code=500, detail="Missing dependency: face_recognition")
    if SVC is None or LabelEncoder is None or normalize is None:
        raise HTTPException(status_code=500, detail="Missing dependency: scikit-learn")


def _check_api_key(x_api_key: Optional[str]):
    if DEFAULT_API_KEY:
        if not x_api_key or x_api_key != DEFAULT_API_KEY:
            raise HTTPException(status_code=401, detail="Unauthorized")


def _sha256_bytes(b: bytes) -> str:
    return hashlib.sha256(b).hexdigest()


def _is_image_file(fn: str) -> bool:
    ext = os.path.splitext(fn.lower())[1]
    return ext in [".jpg", ".jpeg", ".png", ".bmp", ".tif", ".tiff", ".webp"]


def _list_employee_images(employee_dir: str) -> List[Tuple[str, str]]:
    pairs = []
    if not os.path.isdir(employee_dir):
        return pairs
    for person in sorted(os.listdir(employee_dir)):
        person_dir = os.path.join(employee_dir, person)
        if not os.path.isdir(person_dir):
            continue
        for root, _, files in os.walk(person_dir):
            for f in files:
                if _is_image_file(f):
                    pairs.append((person, os.path.join(root, f)))
    return pairs


def _load_image_rgb(path: str) -> np.ndarray:
    return face_recognition.load_image_file(path)


def _extract_face_encodings_from_image(img_rgb: np.ndarray, detection_model: str, num_jitters: int, min_face_size: int):
    locs = face_recognition.face_locations(img_rgb, model=detection_model)
    filtered = []
    for (top, right, bottom, left) in locs:
        w = max(0, right - left)
        h = max(0, bottom - top)
        if w >= min_face_size and h >= min_face_size:
            filtered.append((top, right, bottom, left))
    encs = face_recognition.face_encodings(img_rgb, known_face_locations=filtered, num_jitters=num_jitters)
    return filtered, encs


def _train_from_dir(employee_dir: str, detection_model: str, num_jitters: int, min_face_size: int):
    _require_deps()
    data = _list_employee_images(employee_dir)
    if not data:
        raise HTTPException(status_code=400, detail=f"No training images found under: {employee_dir}")

    X = []
    y = []
    per_class_counts = {}
    bad = []

    for label, path in data:
        try:
            img = _load_image_rgb(path)
            _, encs = _extract_face_encodings_from_image(img, detection_model, num_jitters, min_face_size)
            if len(encs) == 0:
                bad.append({"label": label, "path": path, "reason": "no_face_detected"})
                continue
            if len(encs) > 1:
                bad.append({"label": label, "path": path, "reason": "multiple_faces_detected_using_first"})
            X.append(encs[0])
            y.append(label)
            per_class_counts[label] = per_class_counts.get(label, 0) + 1
        except Exception as e:
            bad.append({"label": label, "path": path, "reason": f"error:{type(e).__name__}"})

    if len(X) < 2 or len(set(y)) < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 samples from at least 2 distinct employees to train.")

    X = np.asarray(X, dtype=np.float32)
    le = LabelEncoder()
    y_enc = le.fit_transform(np.asarray(y))

    clf = SVC(kernel="linear", probability=True, class_weight="balanced", random_state=42)
    clf.fit(X, y_enc)

    model = {
        "app": APP_NAME,
        "created_at": time.time(),
        "employee_dir": os.path.abspath(employee_dir),
        "detection_model": detection_model,
        "num_jitters": num_jitters,
        "min_face_size": min_face_size,
        "label_encoder": le,
        "classifier": clf,
        "classes": list(le.classes_),
        "train_counts": per_class_counts,
        "train_samples": int(len(X)),
        "bad_samples": bad,
        "version": _sha256_bytes(pickle.dumps((list(le.classes_), per_class_counts, len(X))))[:16],
    }
    return model


def _save_model(model: dict, model_path: str):
    tmp = model_path + ".tmp"
    with open(tmp, "wb") as f:
        pickle.dump(model, f)
    os.replace(tmp, model_path)


def _load_model(model_path: str) -> dict:
    _require_deps()
    if not os.path.isfile(model_path):
        raise HTTPException(status_code=404, detail=f"Model not found: {model_path}")
    with open(model_path, "rb") as f:
        model = pickle.load(f)
    return model


def _ensure_model_loaded(model_path: str) -> dict:
    global _model
    with _model_lock:
        if _model is None:
            _model = _load_model(model_path)
        return _model


def _softmax(x: np.ndarray) -> np.ndarray:
    x = x - np.max(x)
    e = np.exp(x)
    s = np.sum(e)
    if s <= 0:
        return np.ones_like(x) / len(x)
    return e / s


def _distance_to_probs(distances: np.ndarray, scale: float) -> np.ndarray:
    d = np.asarray(distances, dtype=np.float64)
    logits = -d * float(scale)
    return _softmax(logits)


def _predict_probs_with_fallback(model: dict, enc: np.ndarray, distance_scale: float):
    clf = model["classifier"]
    le = model["label_encoder"]
    classes = model["classes"]

    probs = None
    method = None

    if hasattr(clf, "predict_proba"):
        try:
            p = clf.predict_proba(enc.reshape(1, -1))[0].astype(np.float64)
            p = np.clip(p, 0.0, 1.0)
            s = float(np.sum(p))
            if s > 0:
                p = p / s
            probs = p
            method = "svm_predict_proba"
        except Exception:
            probs = None
            method = None

    if probs is None:
        try:
            if hasattr(clf, "decision_function"):
                scores = clf.decision_function(enc.reshape(1, -1))
                if scores.ndim == 1:
                    scores = scores.reshape(1, -1)
                probs = _softmax(scores[0].astype(np.float64))
                method = "svm_decision_softmax"
            else:
                raise RuntimeError("No proba/decision_function available")
        except Exception:
            raise HTTPException(status_code=500, detail="Model cannot produce probability distribution.")

    dist = None
    try:
        if hasattr(clf, "support_vectors_"):
            sv = clf.support_vectors_.astype(np.float32)
            d = np.linalg.norm(sv - enc.astype(np.float32), axis=1)
            dist = float(np.min(d)) if d.size else None
    except Exception:
        dist = None

    dist_to_class_probs = None
    try:
        if hasattr(clf, "support_vectors_"):
            sv = clf.support_vectors_.astype(np.float32)
            sv_labels = clf.predict(sv)
            cls_count = len(classes)
            per_class_min = np.full((cls_count,), np.inf, dtype=np.float64)
            enc32 = enc.astype(np.float32)
            d = np.linalg.norm(sv - enc32, axis=1)
            for i in range(len(d)):
                c = int(sv_labels[i])
                if d[i] < per_class_min[c]:
                    per_class_min[c] = float(d[i])
            finite = np.isfinite(per_class_min)
            if not np.all(finite):
                max_f = np.max(per_class_min[finite]) if np.any(finite) else 1.0
                per_class_min[~finite] = max_f + 1.0
            dist_to_class_probs = _distance_to_probs(per_class_min, distance_scale)
    except Exception:
        dist_to_class_probs = None

    out = []
    for i, name in enumerate(classes):
        out.append({
            "class": str(name),
            "probability": float(probs[i]) if i < len(probs) else 0.0,
            "distance_proxy_probability": float(dist_to_class_probs[i]) if dist_to_class_probs is not None else None
        })

    out.sort(key=lambda r: r["probability"], reverse=True)

    return {
        "distribution": out,
        "top_class": out[0]["class"] if out else None,
        "top_probability": out[0]["probability"] if out else None,
        "method": method,
        "min_support_vector_distance": dist,
    }


app = FastAPI(title=APP_NAME, version="1.0.0")


@app.get("/health")
def health():
    return {"status": "ok", "app": APP_NAME}


@app.post("/train")
def train(
    req: TrainRequest,
    x_api_key: Optional[str] = Query(default=None, alias="x-api-key")
):
    _check_api_key(x_api_key)
    model = _train_from_dir(req.employee_dir, req.detection_model, req.num_jitters, req.min_face_size)
    _save_model(model, req.model_path)
    with _model_lock:
        global _model
        _model = model
    return {
        "status": "trained",
        "model_path": os.path.abspath(req.model_path),
        "model_version": model["version"],
        "classes": model["classes"],
        "train_samples": model["train_samples"],
        "train_counts": model["train_counts"],
        "bad_samples": model["bad_samples"],
    }


@app.post("/load")
def load_model(
    model_path: str = Body(default=DEFAULT_MODEL_PATH, embed=True),
    x_api_key: Optional[str] = Query(default=None, alias="x-api-key")
):
    _check_api_key(x_api_key)
    model = _load_model(model_path)
    with _model_lock:
        global _model
        _model = model
    return {
        "status": "loaded",
        "model_path": os.path.abspath(model_path),
        "model_version": model.get("version"),
        "classes": model.get("classes", []),
        "train_samples": model.get("train_samples"),
        "employee_dir": model.get("employee_dir"),
    }


