@app.post("/predict", response_model=PredictResponse)
async def predict(
    file: UploadFile = File(...),
    model_path: str = Query(default=DEFAULT_MODEL_PATH),
    detection_model: str = Query(default=DEFAULT_DETECTION_MODEL),
    num_jitters: int = Query(default=DEFAULT_NUM_JITTERS),
    min_face_size: int = Query(default=DEFAULT_MIN_FACE_SIZE),
    max_faces: int = Query(default=DEFAULT_MAX_FACES),
    distance_scale: float = Query(default=DEFAULT_DISTANCE_SCALE),
    x_api_key: Optional[str] = Query(default=None, alias="x-api-key")
):
    _check_api_key(x_api_key)
    _require_deps()
    model = _ensure_model_loaded(model_path)

    content = await file.read()
    if not content:
        raise HTTPException(status_code=400, detail="Empty file upload")

    try:
        img = face_recognition.load_image_file(io.BytesIO(content))
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image data")

    locs, encs = _extract_face_encodings_from_image(img, detection_model, num_jitters, min_face_size)
    if len(encs) == 0:
        return {
            "model_version": model.get("version"),
            "faces_detected": 0,
            "results": []
        }

    results = []
    n = min(len(encs), int(max_faces))
    for i in range(n):
        enc = np.asarray(encs[i], dtype=np.float32)
        (top, right, bottom, left) = locs[i]
        pred = _predict_probs_with_fallback(model, enc, distance_scale)
        results.append({
            "face_index": i,
            "bbox": {"top": int(top), "right": int(right), "bottom": int(bottom), "left": int(left)},
            "top_class": pred["top_class"],
            "top_probability": pred["top_probability"],
            "probability_method": pred["method"],
            "min_support_vector_distance": pred["min_support_vector_distance"],
            "distribution": pred["distribution"],
        })

    return {
        "model_version": model.get("version"),
        "faces_detected": int(len(encs)),
        "results": results
    }


